INSERT INTO BOOKING
	( BOOKING_ID
	, SCHEDULE_ID
	, MEMBER_ID
	, BOOKER_NM
	, BOOKER_TEL
	, BOOKER_EMAIL
	, TOTAL_QTY
	, TOTAL_AMT
	, BOOKING_STATUS
	, PAYMENT_STATUS
	, REG_DT )
VALUES
	( #{bookingId}
	, #{scheduleId}
	, #{memberId}
	, #{bookerNm}
	, #{bookerTel}
	, #{bookerEmail}
	, #{totalQty}
	, #{totalAmt}
	, #{bookingStatus}
	, #{paymentStatus}
	, NOW() )

mapper.update:
UPDATE BOOKING
SET BOOKING_STATUS  = #{bookingStatus}
  , PAYMENT_STATUS  = #{paymentStatus}
  , TOTAL_QTY       = #{totalQty}
  , TOTAL_AMT       = #{totalAmt}
WHERE BOOKING_ID = #{bookingId}
